const KEYWORD_CATEGORIES = {
  fabrication: [
    'CNC', 'cnc', 'laser', 'cutting', 'cut', 'router', 'machine', 'shop', 
    'workshop', 'build', 'building', 'built', 'material', 'wood', 'acrylic',
    'tolerance', 'precision', 'fabrication', 'manufacturing', 'mill', 'toolpath'
  ],

  gameDesign: [
    'game design', 'environmental storytelling', 'flow', 'player', 'level design',
    'UX', 'user experience', 'feedback loop', 'pacing', 'guidance', 'invisible',
    'intuitive', 'discovery', 'progression', 'tutorial'
  ],

  process: [
    'how to', 'step', 'process', 'workflow', 'method', 'approach', 'technique',
    'procedure', 'tutorial', 'guide', 'breakdown', 'framework', 'system'
  ],

  story: [
    'learned', 'lesson', 'mistake', 'failed', 'failure', 'first time', 'journey',
    'started', 'began', 'experience', 'happened', 'realized', 'discovered'
  ],

  opinion: [
    'think', 'believe', 'opinion', 'take', 'problem', 'issue', 'wrong', 'should',
    'shouldn\'t', 'better way', 'unpopular opinion', 'hot take', 'controversial'
  ],

  technical: [
    'specification', 'specs', 'parameter', 'setting', 'configuration', 'setup',
    'calibration', 'measurement', 'dimension', 'angle', 'speed', 'feed rate'
  ],

  philosophy: [
    'principle', 'framework', 'approach', 'philosophy', 'mindset', 'thinking',
    'believe', 'value', 'important', 'matters', 'care about'
  ],

  experiential: [
    'experience', 'space', 'environment', 'installation', 'interactive', 
    'responsive', 'immersive', 'spatial', 'physical space', 'user journey'
  ],

  industry: [
    'industry', 'market', 'trend', 'company', 'business', 'client', 'project',
    'studio', 'agency', 'designer', 'maker', 'fabricator'
  ]
};

function detectKeywords(text) {
  const textLower = text.toLowerCase();
  const detected = {};

  Object.keys(KEYWORD_CATEGORIES).forEach(category => {
    detected[category] = KEYWORD_CATEGORIES[category].filter(keyword => 
      textLower.includes(keyword.toLowerCase())
    );
  });

  return detected;
}
```

